        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check jira_state.json"}

    # Try both jira_state.json and jira_data.json
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        jira_path = Path(external_services_path) / "jira_data.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"Neither jira_state.json nor jira_data.json found at {external_services_path}"}

    with open(jira_path, "r") as f:
        data = json.load(f)

    # Flatten all possible issue structures into a list of issue dicts
    all_issues = []

    def collect_issues(obj, depth=0):
        if depth > 10:
            return
        if isinstance(obj, dict):
            # Check if this dict itself looks like an issue (has summary or description or key)
            if any(k in obj for k in ["summary", "description", "key", "fields"]):
                all_issues.append(obj)
            # Recurse into values
            for k, v in obj.items():
                if isinstance(v, (dict, list)):
                    collect_issues(v, depth + 1)
        elif isinstance(obj, list):
            for item in obj:
                if isinstance(item, (dict, list)):
                    collect_issues(item, depth + 1)

    collect_issues(data)

    # Helper to extract all text from an object
    def get_all_text(obj, depth=0):
        if depth > 10:
            return ""
        if isinstance(obj, str):
            return obj + " "
        elif isinstance(obj, dict):
            return " ".join(get_all_text(v, depth + 1) for v in obj.values())
        elif isinstance(obj, list):
            return " ".join(get_all_text(item, depth + 1) for item in obj)
        else:
            return str(obj) + " "

    # Helper to get summary from an issue dict
    def get_summary(issue):
        # Direct summary field
        if "summary" in issue and isinstance(issue["summary"], str):
            return issue["summary"]
        # Nested in fields
        if "fields" in issue and isinstance(issue["fields"], dict):
            if "summary" in issue["fields"] and isinstance(issue["fields"]["summary"], str):
                return issue["fields"]["summary"]
        # Check key field as well
        if "key" in issue and isinstance(issue["key"], str):
            return issue["key"]
        return ""

    # Helper to get assignee from an issue dict
