            val = issue["assignee"]
            if isinstance(val, str):
                return val
            elif isinstance(val, dict):
                # Could be {"name": ..., "displayName": ...}
                for k in ["displayName", "display_name", "name", "accountId"]:
                    if k in val and isinstance(val[k], str):
                        return val[k]
                return get_all_text(val)
        # Nested in fields
