            fields = issue["fields"]
            if "assignee" in fields:
                val = fields["assignee"]
                if isinstance(val, str):
                    return val
                elif isinstance(val, dict):
                    for k in ["displayName", "display_name", "name", "accountId"]:
                        if k in val and isinstance(val[k], str):
                            return val[k]
                    return get_all_text(val)
        return ""

    # Search for the target issue by summary containing 'OFFBOARD-Teodoor-04192026'
    target_summary_lower = "offboard-teodoor-04192026"

