            all_summaries.append(summary)
        full_text_of_issue = get_all_text(issue).lower()
        # Check if the summary or any text in the issue contains the target summary string
        if target_summary_lower in summary.lower().replace(" ", "").replace("_", "-") or target_summary_lower in full_text_of_issue.replace(" ", "").replace("_", "-"):
            target_issue = issue
            matched_summary = summary
            break

    # If not found with exact match, try looser matching
