                target_issue = issue
                matched_summary = summary
                break

    if target_issue is None:
        # Also check if the key or any top-level key in data matches
        if isinstance(data, dict):
            for k, v in data.items():
                if target_summary_lower in str(k).lower().replace(" ", "").replace("_", "-"):
                    target_issue = v if isinstance(v, dict) else {"_raw": v}
                    matched_summary = str(k)
                    break

    if target_issue is None:
