    required_parts = [
        "separation",
        "gerta teodoor",
        "10741",
        "voluntary resignation",
        "04/19/2026"
    ]

    all_msg_texts = []

    for msg in channel_messages:
        if not isinstance(msg, dict):
            continue
        text = str(msg.get("text", ""))
        all_msg_texts.append(text[:100])
        text_lower = text.lower()

        # Check all required parts present (case-insensitive)
        missing = [part for part in required_parts if part not in text_lower]
        if missing:
            continue

        # Check that a Jira ticket ID is mentioned
        has_jira_ref = False
        if jira_key.lower() in text_lower:
            has_jira_ref = True
        elif re.search(r'offboard[\-_]teodoor[\-_]\d+', text, re.IGNORECASE):
            has_jira_ref = True
        elif re.search(r'offboard[\-_]\d+', text, re.IGNORECASE):
            has_jira_ref = True
        elif re.search(r'HR[\-_]\d+', text, re.IGNORECASE):
            has_jira_ref = True

        if not has_jira_ref:
            continue

        return {"pass": True, "score": 1.0, "feedback": f"Found Slack message in #hr-offboarding with separation info for Gerta Teodoor and Jira ticket reference '{jira_key}'. Message: {text[:300]}"}

    # If we get here, check partial matches for better feedback
    partial_info = []
    for msg in channel_messages:
        if not isinstance(msg, dict):
            continue
        text = str(msg.get("text", ""))
        text_lower = text.lower()
        if "teodoor" in text_lower or "separation" in text_lower:
            missing = [part for part in required_parts if part not in text_lower]
            has_jira = jira_key.lower() in text_lower or bool(re.search(r'offboard', text, re.IGNORECASE))
