from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json for sent emails."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found at {mailbox_path}"}

    with open(mailbox_path, "r", encoding="utf-8") as f:
        mailbox_data = json.load(f)

    emails = mailbox_data.get("emails", [])

    # Find sent emails to j.park@crestwood.edu with matching subject
    target_to = "j.park@crestwood.edu"
    target_subject = "Access Revocation Request — Teodoor, 10741"

    # Also accept common dash variants
    def normalize_dashes(s):
        # Replace em-dash, en-dash, and various Unicode dashes with a standard dash for comparison
        return re.sub(r'[\u2014\u2013\u2012\u2015\u2010\u002D\uFE58\uFE63\uFF0D—–-]', '-', s)

    target_subject_normalized = normalize_dashes(target_subject.lower().strip())

    matching_emails = []
    for email in emails:
        folder = email.get("folder", "").lower()
        to_addr = email.get("to_addr", "").lower().strip()
        subject = email.get("subject", "").strip()
        subject_normalized = normalize_dashes(subject.lower().strip())

        if folder == "sent" and target_to.lower() in to_addr and target_subject_normalized == subject_normalized:
            matching_emails.append(email)

    if not matching_emails:
        # Provide more debugging info
        sent_emails = [e for e in emails if e.get("folder", "").lower() == "sent"]
        sent_subjects = [e.get("subject", "") for e in sent_emails]
        sent_tos = [e.get("to_addr", "") for e in sent_emails]
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"No sent email found to '{target_to}' with subject '{target_subject}'. Found {len(sent_emails)} sent emails. Subjects: {sent_subjects}. To addresses: {sent_tos}"
        }

    # Now check the body content of matching emails
    required_fragments = [
        "Hi Jenna",
        "revoke all system access",
        "Gerta Teodoor",
        "10741",
        "04/19/2026",
        "End of business on last day",
        "email",
        "VPN",
        "building access",
        "university systems",
        "confirm when complete",
        "Crestwood University",
        "Office of Human Resources",
        "hr@crestwood.edu"
    ]

    for email in matching_emails:
        body = email.get("body_text", "")
        # Normalize whitespace for comparison
        body_normalized = re.sub(r'\s+', ' ', body).strip().lower()

        missing = []
        for frag in required_fragments:
            frag_normalized = re.sub(r'\s+', ' ', frag).strip().lower()
            if frag_normalized not in body_normalized:
                missing.append(frag)

        if not missing:
            return {
                "pass": True,
                "score": 1.0,
                "feedback": f"Found sent email to '{target_to}' with correct subject and all required body content present."
            }
        else:
            # Partial match - check how many are present
            found_count = len(required_fragments) - len(missing)
            total = len(required_fragments)
            # Be generous: if only 1-2 minor fragments missing, still pass
            if len(missing) <= 1:
                return {
                    "pass": True,
                    "score": 0.9,
                    "feedback": f"Found sent email with nearly all required content ({found_count}/{total}). Minor missing fragments: {missing}"
                }
            else:
                return {
                    "pass": False,
                    "score": found_count / total,
                    "feedback": f"Found sent email to '{target_to}' with correct subject, but missing {len(missing)} required body fragments: {missing}. Body preview: {body[:500]}"
                }

    return {"pass": False, "score": 0.0, "feedback": "No matching email passed body content checks."}

